                {"Concepto": "Mix híbrido bruto", "Valor MM": float(recommended["Ahorro anual híbrido CLP"]) / 1_000_000, "Color": client_blue_2},
                {"Concepto": "Mix híbrido neto", "Valor MM": rec_net_savings / 1_000_000, "Color": client_blue_5},
